          const faq=(BL.faq||[]).map(f=>({q:f.q.replace(/\{month\}/g,b.monthName).replace(/\{stone\}/g,b.stone),a:f.a.replace(/\{month\}/g,b.monthName).replace(/\{stone\}/g,b.stone)}));
