          const bar=(lbl,v,g)=>`<div class="cp-bar"><div class="cp-bl"><span>${esc(lbl)}</span><span>${v}%</span></div><div class="cp-bt"><div class="cp-bf" style="width:${v}%;background:${g};"></div></div></div>`;
          const more=CZ_ANIMALS.map((an,k)=>{if(k===ia)return'';const lo=Math.min(ia,k),hi=Math.max(ia,k);return C.animals[k]?`<a href="${SITE_URL}/${zl}/${czM[2]}/${CZ_ANIMALS[lo]}-${CZ_ANIMALS[hi]}/">${esc(nameA)} &amp; ${esc(C.animals[k].name)}</a>`:'';}).join('');
          const faq=[{q:(C.faqTpl[0]?C.faqTpl[0].q.replace(/\{A\}/g,nameA).replace(/\{B\}/g,nameB):''),a:`${sc.overall}% — ${verdict}`}].concat((C.faqTpl||[]).slice(1).map(f=>({q:f.q.replace(/\{A\}/g,nameA).replace(/\{B\}/g,nameB),a:f.a.replace(/\{A\}/g,nameA).replace(/\{B\}/g,nameB)})));
