          ogT = (cLang==='ko')?`${bd1.slice(0,4)}년생 × ${bd2.slice(0,4)}년생 궁합 결과`:`Compatibility: ${bd1.slice(0,4)} × ${bd2.slice(0,4)}`;
          ogD = (cLang==='ko')?'사주팔자 궁합 분석 결과를 확인하세요.':CL.desc;
